import Anthropic from '@anthropic-ai/sdk';
import { PluginError, type Plugin } from '@ax/core';

const PLUGIN_NAME = '@ax/llm-anthropic';
const DEFAULT_MODEL = 'claude-haiku-4-5-20251001';
const DEFAULT_MAX_TOKENS = 4096;
const TRANSIENT_STATUSES = new Set([429, 500, 502, 503, 504]);
const DEFAULT_RETRY_DELAY_MS = 1000;

export interface LlmAnthropicConfig {
  apiKey?: string;
  defaultModel?: string;
  defaultMaxTokens?: number;
  retryDelayMs?: number;
  // For tests: inject a stub Anthropic client.
  clientFactory?: (apiKey: string) => Anthropic;
}

export function createLlmAnthropicPlugin(cfg: LlmAnthropicConfig = {}): Plugin {
  return {
    manifest: {
      name: PLUGIN_NAME,
      version: '0.0.0',
      registers: ['llm:call'],
      calls: [],
      subscribes: [],
    },
    async init({ bus }) {
      const apiKey = cfg.apiKey ?? process.env.ANTHROPIC_API_KEY;
      if (!apiKey || apiKey.length === 0) {
        throw new PluginError({
          code: 'init-failed',
          plugin: PLUGIN_NAME,
          hookName: 'init',
          message: 'ANTHROPIC_API_KEY not set',
        });
      }
      const client = cfg.clientFactory ? cfg.clientFactory(apiKey) : new Anthropic({ apiKey });
      bus.registerService<LlmCallInput, LlmCallOutput>(
        'llm:call',
        PLUGIN_NAME,
        async (_ctx, input) => callWithRetry(client, input, cfg),
      );
    },
  };
}

async function callWithRetry(
  client: Anthropic,
  input: LlmCallInput,
  cfg: LlmAnthropicConfig,
): Promise<LlmCallOutput> {
  const req = toAnthropicRequest(input, cfg);
  let lastErr: unknown;
  for (let attempt = 0; attempt < 2; attempt++) {
    try {
      const res = await client.messages.create(req);
      return fromAnthropicResponse(res);
    } catch (e) {
      lastErr = e;
      if (attempt === 0 && isTransient(e)) {
        await sleep(cfg.retryDelayMs ?? DEFAULT_RETRY_DELAY_MS);
        continue;
      }
      throw new PluginError({
        code: 'unknown',
        plugin: PLUGIN_NAME,
        hookName: 'llm:call',
        message: `Anthropic API call failed: ${errorMessage(e)}`,
        cause: e instanceof Error ? e : undefined,
      });
    }
  }
  throw new PluginError({
    code: 'unknown',
    plugin: PLUGIN_NAME,
    hookName: 'llm:call',
    message: `Anthropic API call exhausted retries: ${errorMessage(lastErr)}`,
  });
}
```

