import type { ContentBlock } from '@ax/ipc-protocol';
import type { Turn } from './types.js';

const SYSTEM_PROMPT = `You generate short, descriptive titles for conversations between a user and an AI assistant. Output ONLY the title ã no quotes, no preamble, no trailing period. Maximum 8 words. Use Title Case. If the conversation is empty or unclear, output exactly: Untitled`;

const TRANSCRIPT_BUDGET = 4000;

export interface BuiltPrompt {
  system: string;
  user: string;
}

export function buildPrompt(turns: Turn[]): BuiltPrompt {
  const lines: string[] = [];
  let used = 0;
  for (const turn of turns) {
    const text = flattenBlocks(turn.contentBlocks);
    if (text.length === 0) continue;
    const label = turn.role === 'user' ? 'User' : turn.role === 'assistant' ? 'Assistant' : 'Tool';
    const line = `${label}: ${text}`;
    if (used + line.length > TRANSCRIPT_BUDGET) break;
    lines.push(line);
    used += line.length;
  }
  return {
    system: SYSTEM_PROMPT,
    user: `Summarize this conversation in ãÊ8 words:\n\n${lines.join('\n')}`,
  };
}

function flattenBlocks(blocks: ContentBlock[]): string {
  return blocks
    .map((b) => {
      if (b.type === 'text') return b.text;
      if (b.type === 'tool_use') return `[tool: ${b.name}]`;
      if (b.type === 'tool_result') return '[result]';
      // thinking, redacted_thinking, image, etc. ã drop.
      return '';
    })
    .filter((s) => s.length > 0)
    .join(' ');
}
```

