  let s = raw.split('\n')[0] ?? '';
  s = s.trim();
  if ((s.startsWith('"') && s.endsWith('"')) || (s.startsWith("'") && s.endsWith("'"))) {
    s = s.slice(1, -1).trim();
  }
  if (s.length === 0) return null;
  if (s === 'Untitled') return null;
  if (s.length > TITLE_MAX) s = s.slice(0, TITLE_MAX).trim();
  return s.length > 0 ? s : null;
}
```

