import {
  PluginError,
  type AgentContext,
  type HookBus,
  type LlmCallInput,
  type LlmCallOutput,
  type Plugin,
} from '@ax/core';
import { buildPrompt } from './prompt.js';
import { validateGeneratedTitle } from './validate.js';
import type {
  GetInput,
  GetOutput,
  SetTitleInput,
  SetTitleOutput,
} from './types.js';

const PLUGIN_NAME = '@ax/conversation-titles';
const TITLE_MODEL = 'claude-haiku-4-5-20251001';
const TITLE_MAX_TOKENS = 32;
const TITLE_TEMPERATURE = 0.3;

interface TurnEndPayload {
  role?: 'user' | 'assistant' | 'tool';
  contentBlocks?: unknown[];
  reqId?: string;
}

export function createConversationTitlesPlugin(): Plugin {
  return {
    manifest: {
      name: PLUGIN_NAME,
      version: '0.0.0',
      registers: [],
      calls: ['llm:call', 'conversations:get', 'conversations:set-title'],
      subscribes: ['chat:turn-end'],
    },
    async init({ bus }) {
      bus.subscribe<TurnEndPayload>(
        'chat:turn-end',
        PLUGIN_NAME,
        async (ctx, payload) => {
          try {
            await handleTurnEnd(bus, ctx, payload);
          } catch (err) {
            ctx.logger.warn('conversation_titles_subscriber_failed', {
              err: err instanceof Error ? err : new Error(String(err)),
              conversationId: ctx.conversationId,
            });
          }
        },
      );
    },
  };
}

async function handleTurnEnd(
  bus: HookBus,
  ctx: AgentContext,
  payload: TurnEndPayload,
): Promise<void> {
  if (payload.role !== 'assistant') return;
  if (ctx.conversationId === undefined) return;
  if (ctx.userId === undefined) return;

  // Skip if title already set or transcript empty.
  const conv = await bus.call<GetInput, GetOutput>('conversations:get', ctx, {
    conversationId: ctx.conversationId,
    userId: ctx.userId,
  });
  if (conv.conversation.title !== null) return;
  if (conv.turns.length === 0) return;

  const prompt = buildPrompt(conv.turns);
  const llmOut = await bus.call<LlmCallInput, LlmCallOutput>('llm:call', ctx, {
    model: TITLE_MODEL,
    maxTokens: TITLE_MAX_TOKENS,
    system: prompt.system,
    messages: [{ role: 'user', content: prompt.user }],
    temperature: TITLE_TEMPERATURE,
  });

  const title = validateGeneratedTitle(llmOut.text);
  if (title === null) {
    ctx.logger.debug('conversation_titles_validation_skipped', {
      conversationId: ctx.conversationId,
      raw: llmOut.text,
    });
    return;
  }

  const result = await bus.call<SetTitleInput, SetTitleOutput>(
    'conversations:set-title',
    ctx,
    {
      conversationId: ctx.conversationId,
      userId: ctx.userId,
      title,
      ifNull: true,
    },
  );
  if (!result.updated) {
    ctx.logger.debug('conversation_titles_already_set', {
      conversationId: ctx.conversationId,
    });
  }
}
```

Note: `ctx.userId` may be required (not undefined-able). Check `AgentContext` shape; remove the undefined check if so. Same for `ctx.logger.debug` ã verify the logger interface.

Note: bus subscribers' "do not throw" posture is enforced by the try/catch wrapper. Confirm by reading how `@ax/conversations`'s `chat:turn-end` subscriber handles errors (it logs via `ctx.logger.warn` and swallows).

### Test cases (`plugin.test.ts`)

Use the project's bus harness pattern (look at `packages/llm-anthropic/src/__tests__/plugin.test.ts` for the `new HookBus()` + `makeAgentContext` + manual hook registration pattern, or `packages/conversations/src/__tests__/subscribe.test.ts`).

Mock `conversations:get`, `llm:call`, `conversations:set-title` by registering stub services on the bus.

Cases:
1. **Manifest** ã `registers: []`, `calls: ['llm:call', 'conversations:get', 'conversations:set-title']`, `subscribes: ['chat:turn-end']`.
2. **No-op on user role** ã fire `chat:turn-end` with `role: 'user'`. Stubs assert NOT called.
3. **No-op on missing conversationId** ã `chat:turn-end` with `role: 'assistant'`, ctx.conversationId undefined. Stubs assert NOT called.
4. **No-op when title already set** ã stub `conversations:get` returns `{ conversation: { title: 'Existing' }, turns: [{ ... }] }`. `llm:call` and `set-title` NOT called.
5. **No-op when transcript empty** ã stub returns `{ conversation: { title: null }, turns: [] }`. `llm:call` and `set-title` NOT called.
6. **Happy path** ã stub `conversations:get` returns 2 turns, title null. `llm:call` returns `{ text: 'My Conversation', stopReason: 'end_turn', usage: {...} }`. `set-title` called once with `{ title: 'My Conversation', ifNull: true }`. Subscriber doesn't throw.
